namespace sv_a57170bc9ef542e5af15662553a39c3b.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

/// <summary>
/// Mutable form model for two-way binding, convertible to the immutable record types.
/// </summary>
public class ApplicationFormModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public List<WorkEntryModel> WorkEntries { get; set; } = [new()];

    public List<ReferenceModel> References { get; set; } = [new(), new()];

    public string CoverLetter { get; set; } = "";

    public JobApplication ToJobApplication() => new(
        new PersonalInfo(FullName, Email, Phone, Address),
        new WorkHistory(WorkEntries.Select(w => w.ToWorkEntry()).ToList()),
        References.Select(r => r.ToReference()).ToList(),
        CoverLetter
    );
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToWorkEntry() => new(
        Company, Title,
        StartDate ?? DateTime.Today,
        IsCurrent ? null : EndDate,
        Description
    );
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToReference() => new(Name, Relationship, Email, Phone);
}

using sv_a57170bc9ef542e5af15662553a39c3b.Models;

namespace sv_a57170bc9ef542e5af15662553a39c3b.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(500);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(200);
        return !string.IsNullOrWhiteSpace(email)
            && email.Contains('@')
            && email.Contains('.');
    }
}

