@page "/apply"
@rendermode InteractiveServer

@using sv_a57170bc9ef542e5af15662553a39c3b.Components.Pages.ApplySteps
@using sv_a57170bc9ef542e5af15662553a39c3b.Models

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnNavigate="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="model" OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 1:
            <WorkHistoryStep Model="model" OnNext="NextStep" OnBack="PrevStep" />
            break;
        case 2:
